 }

+#[derive(Debug, Clone, Serialize, Deserialize)]
+struct SetupSelfHealCache {
+    schema_version: u32,
+    project_dir: String,
+    server_url: String,
+    token_fingerprint: String,
+    target_agents: Vec<String>,
+    skip_user_config: bool,
